using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change #1 — Discriminator property renamed.
            // EF Core 9 defaults to "$type" instead of "Discriminator".
            // Existing 500K documents use "Discriminator", so keep the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #2 — Id format changed.
            // EF Core 9 no longer prepends the discriminator to the id value.
            // Existing documents have ids like "Product|123", so preserve that format.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonPropertyName("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change #3 — HasIndex throws at model build time.
            // Cosmos DB manages indexes server-side; the EF Core Cosmos provider
            // no longer silently ignores HasIndex — it throws InvalidOperationException.
            // The previous .HasIndex(p => p.Sku) call has been removed.
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = string.Empty;
}

// Reproduces the EF Core 8 "Discriminator|Key" id format so existing documents
// remain readable without a data migration.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString() ?? entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue;
        return $"{discriminator}|{key}";
    }
}

