class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe because we explicitly kept "Discriminator" as the
        // discriminator property name in OnModelCreating (EF Core 9 would default to "$type").
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Breaking change #4 — Synchronous LINQ queries removed.
        // EF Core 9 Cosmos provider no longer supports .ToList(), .First(), etc.
        // All queries must use async counterparts.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

